  'function' => 
  array (
    'name' => 'gif_validator',
    'description' => 'Validate animated GIF files in the workspace. Checks GIF89a header, reads Graphics Control Extension blocks for frame timing, counts frames, verifies Netscape Application Extension for looping, and reports animation metadata. Pure PHP, no shell. Never throws.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
