if (! function_exists('gif_validator')) {
    function gif_validator($path = null, $timeout = null)
    {
        $path = $path ?? getcwd() . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
        $timeout = $timeout ?? 5;
        $start = microtime(true);

        $prefix = getcwd() . DIRECTORY_SEPARATOR;
        $fullPath = $path;
        if (strpos($path, $prefix) !== 0 && strpos($path, 'storage') === 0) {
            $fullPath = $prefix . $path;
        }

        $files = [];
        if (is_dir($fullPath)) {
            $it = new DirectoryIterator($fullPath);
            foreach ($it as $f) {
                if ($f->isFile() && strtolower($f->getExtension()) === 'gif') {
                    $files[] = $f->getPathname();
                }
            }
        } elseif (is_file($fullPath)) {
            $files = [$fullPath];
        } else {
            return ['error' => 'Path not found: ' . $path];
        }

        sort($files);
        $results = [];

        foreach ($files as $gifPath) {
            $name = basename($gifPath);
            $size = filesize($gifPath);
            
            if ($size < 14) {
                $results[] = ['file' => $name, 'valid' => false, 'error' => 'File too small for GIF header', 'size' => $size];
                continue;
            }
            
            $data = @file_get_contents($gifPath);
            if ($data === false) {
                $results[] = ['file' => $name, 'valid' => false, 'error' => 'Cannot read file', 'size' => $size];
                continue;
            }
            
            $errors = [];
            $info = [
                'has_netscape_ext' => false,
                'frame_count' => 0,
                'loop_count' => 0,
                'frame_delays' => [],
                'has_transparency' => false,
            ];
            
            // Check header
            $header = substr($data, 0, 6);
            if ($header !== 'GIF89a' && $header !== 'GIF87a') {
                $errors[] = 'Invalid GIF header: ' . bin2hex($header);
            } else {
                $info['version'] = $header;
            }
            
            // Check for Netscape Application Extension (looping)
            $nsPos = strpos($data, "\x21\xFF\x0BNETSCAPE2.0");
            if ($nsPos !== false) {
                $info['has_netscape_ext'] = true;
                $loop_data = substr($data, $nsPos + 16, 2);
                if (strlen($loop_data) === 2) {
                    $info['loop_count'] = unpack('v', $loop_data)[1];
                }
            }
            
            // Count frames by finding all Image Descriptor markers (0x2C)
            $frames = [];
            $offset = 0;
            while (($pos = strpos($data, "\x2C", $offset)) !== false) {
                $frames[] = $pos;
                $offset = $pos + 1;
            }
            $info['frame_count'] = count($frames);
            
            // Find GCE blocks for frame timing
            $gcePos = 0;
            $delays = [];
            while (($gcePos = strpos($data, "\x21\xF9\x04", $gcePos)) !== false) {
                if ($gcePos + 8 <= strlen($data)) {
                    $delay_raw = substr($data, $gcePos + 4, 2);
                    $delay_cs = unpack('v', $delay_raw)[1];
                    $delays[] = $delay_cs;
                    
                    // Check transparency
                    $packed = ord($data[$gcePos + 3]);
                    $info['has_transparency'] = $info['has_transparency'] || (($packed & 0x01) !== 0);
                }
                $gcePos += 3;
            }
            $info['frame_delays'] = $delays;
            
            // Check for trailer byte
            if (substr($data, -1) !== "\x3B") {
                $errors[] = 'Missing GIF trailer (0x3B)';
            }
            
            // Sanity: animated GIF should have Netscape or multiple frames or GCE
            if (!$info['has_netscape_ext'] && $info['frame_count'] <= 1 && empty($delays)) {
                $info['animated'] = false;
            } else {
                $info['animated'] = true;
            }
            
            $results[] = [
                'file' => $name,
                'size' => $size,
                'valid' => empty($errors),
                'errors' => empty($errors) ? null : $errors,
                'info' => $info,
            ];
        }

        $valid = 0;
        $invalid = 0;
        foreach ($results as $r) {
            if ($r['valid']) $valid++;
            else $invalid++;
        }

        return [
            'files_checked' => count($files),
            'valid_count' => $valid,
            'invalid_count' => $invalid,
            'elapsed_seconds' => round(microtime(true) - $start, 4),
            'results' => $results,
        ];
    }
}
